using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.WriteLine("Proqram başladı.");
        await DoWorkAsync();
        Console.WriteLine("Proqram bitdi.");
    }

    static async Task DoWorkAsync()
    {
        Console.WriteLine("İş başlayır...");
        await Task.Delay(2000); // 2 saniyəlik gecikmə
        Console.WriteLine("İş tamamlandı.");
    }
}
// Output:
// Proqram başladı.
// İş başlayır...
// (2 saniyə gözləyir)
// İş tamamlandı.
// Proqram bitdi.

using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.WriteLine("Hesablama başlayır...");
        int result = await CalculateSumAsync(5, 10);
        Console.WriteLine($"Nəticə: {result}");
    }

    static async Task<int> CalculateSumAsync(int a, int b)
    {
        await Task.Delay(1000); // 1 saniyəlik gecikmə
        return a + b;
    }
}
// Output:
// Hesablama başlayır...
// (1 saniyə gözləyir)
